def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.3:
            for k in range(1, 5):
                score += ((1 - ratio) ** k) * (k * 0.7)
            if capacity % 2 == 0:
                score *= 0.9
            else:
                score *= 1.1
            if score > 3:
                score /= 2
        elif 0.3 <= ratio < 0.7:
            factorial = 1
            for n in range(1, int(capacity) + 1):
                factorial *= n
                if factorial > 1e6:
                    break
            score += np.log1p(ratio * factorial % 1000)
            if (int(capacity) % 3 == 0) and (item % 0.5 == 0):
                score += 2
            else:
                score -= 1
        elif 0.7 <= ratio <= 1:
            for m in range(1, 4):
                increment = (ratio ** m) * (m ** 2)
                score += increment
            if capacity - item < 1:
                score += 5
            else:
                score -= (capacity - item) * 0.5
            if score < 0:
                score = abs(score) * 0.3
        else:
            penalty = 0
            for p in range(1, 6):
                penalty += ((ratio - 1) ** p) * p
            score = penalty * 12
            if capacity < item * 1.2:
                score += 7
            if (int(capacity * 10) % 5 == 0) and (int(item * 10) % 7 == 0):
                score -= 3
        if capacity > 100:
            score /= np.sqrt(capacity)
        elif capacity < 10:
            score *= 1.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        fill_value = np.max(finite_priorities) * 15
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
